/**
 * Gallery: a JSON index + day-bucketed image files for everything generated by
 * the image-gen connectors (see imageGen.ts). Mirrors the runLog.ts storage
 * shape (day dirs under the data dir) and the jsonStore.ts persistence
 * conventions (atomic write, 0700 dir), but keeps images indefinitely — no
 * rotation like run transcripts.
 */

import { randomBytes } from "node:crypto";
import { existsSync, mkdirSync, unlinkSync, writeFileSync } from "node:fs";
import { join } from "node:path";
import { dataPath, loadJson, saveJson } from "./jsonStore.js";
import { semanticSearch, type SearchItem } from "./semanticSearch.js";

export interface GalleryImage {
  id: string;
  /** Connector id that produced this image, e.g. "recraft" or "ideogram". */
  provider: string;
  prompt: string;
  tags: string[];
  createdAt: number;
  /** Path relative to the data dir, e.g. "gallery/2026-07-01/<id>.png". */
  path: string;
  width?: number;
  height?: number;
  /** Telegram chat id that triggered generation, if any. */
  sourceChat?: number;
}

interface GalleryFile {
  images: GalleryImage[];
}

const FILE = "gallery.json";

function load(): GalleryFile {
  return loadJson<GalleryFile>(FILE, { images: [] });
}

function persist(data: GalleryFile): void {
  saveJson(FILE, data);
}

function today(): string {
  const d = new Date();
  const pad = (n: number) => String(n).padStart(2, "0");
  return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}`;
}

function dayDir(date: string): string {
  const dir = dataPath(join("gallery", date));
  if (!existsSync(dir)) mkdirSync(dir, { recursive: true, mode: 0o700 });
  return dir;
}

export interface SaveImageInput {
  provider: string;
  prompt: string;
  bytes: Buffer;
  /** File extension without the dot, defaults to "png". */
  ext?: string;
  tags?: string[];
  width?: number;
  height?: number;
  sourceChat?: number;
}

/** Write generated image bytes to disk and add it to the gallery index. */
export function saveGeneratedImage(input: SaveImageInput): GalleryImage {
  const date = today();
  const id = randomBytes(9).toString("base64url");
  const ext = input.ext ?? "png";
  dayDir(date);
  const relPath = join("gallery", date, `${id}.${ext}`);
  writeFileSync(dataPath(relPath), input.bytes, { mode: 0o600 });

  const image: GalleryImage = {
    id,
    provider: input.provider,
    prompt: input.prompt,
    tags: input.tags ?? [],
    createdAt: Date.now(),
    path: relPath,
    width: input.width,
    height: input.height,
    sourceChat: input.sourceChat,
  };
  const data = load();
  data.images.unshift(image);
  persist(data);
  return image;
}

export interface GalleryFilter {
  tag?: string;
  provider?: string;
  /** Epoch-ms inclusive lower bound on createdAt. */
  from?: number;
  /** Epoch-ms inclusive upper bound on createdAt. */
  to?: number;
  /** Free-text query over prompt + tags, ranked via semanticSearch. */
  q?: string;
}

/** List images matching filter, newest first (or by search relevance when `q` is set). */
export async function listImages(filter: GalleryFilter = {}): Promise<GalleryImage[]> {
  let images = load().images;
  if (filter.provider) images = images.filter((i) => i.provider === filter.provider);
  if (filter.tag) images = images.filter((i) => i.tags.includes(filter.tag!));
  if (filter.from !== undefined) images = images.filter((i) => i.createdAt >= filter.from!);
  if (filter.to !== undefined) images = images.filter((i) => i.createdAt <= filter.to!);

  if (filter.q && filter.q.trim()) {
    const items: SearchItem[] = images.map((i) => ({ id: i.id, text: `${i.prompt} ${i.tags.join(" ")}` }));
    const hits = await semanticSearch(items, filter.q, images.length || 1);
    const order = new Map(hits.map((h, idx) => [h.item.id, idx]));
    images = images.filter((i) => order.has(i.id)).sort((a, b) => order.get(a.id)! - order.get(b.id)!);
  }
  return images;
}

export function getImage(id: string): GalleryImage | undefined {
  return load().images.find((i) => i.id === id);
}

export function updateImage(id: string, patch: { tags?: string[] }): GalleryImage | undefined {
  const data = load();
  const image = data.images.find((i) => i.id === id);
  if (!image) return undefined;
  if (patch.tags) image.tags = patch.tags;
  persist(data);
  return image;
}

export function deleteImage(id: string): boolean {
  const data = load();
  const idx = data.images.findIndex((i) => i.id === id);
  if (idx === -1) return false;
  const [image] = data.images.splice(idx, 1);
  persist(data);
  try {
    const full = dataPath(image.path);
    if (existsSync(full)) unlinkSync(full);
  } catch {
    // best-effort cleanup
  }
  return true;
}

/** Distinct tags across the whole gallery, for panel filter chips. */
export function listTags(): string[] {
  const set = new Set<string>();
  for (const img of load().images) for (const t of img.tags) set.add(t);
  return Array.from(set).sort();
}
